+      const serverUrl =
+        process.env.AGENTLOGS_SERVER_URL?.trim() || process.env.SERVER_URL?.trim() || "https://agentlogs.ai";
+      result.push({
+        name: "prod",
+        baseURL: serverUrl,
+        user: { id: "ci", email: "ci@agentlogs.ai", name: "CI" },
+        lastLoginTime: new Date().toISOString(),
+        token: envToken,
+      });
+    }
